//-----------------------------------------------------------------------------
// CreateCommands                                               CATIPRDWorkshopAddin
//-----------------------------------------------------------------------------
void MRFPrdAddin::CreateCommands ()
{
	//Creates Command MRFAssembleCmd										  
	CATAfrCommandHeader::CATCreateCommandHeader("MRFAssyCmdHdr",
		"MRFAssembleCmd",
		"MRFAssembleCmd",
		(void *)NULL,
		"MRFAssyCmdHeader",
		CATFrmAvailable);

	CATAfrCommandHeader::CATCreateCommandHeader("MRFTyreSurfDepthAnsysCmdHdr",
		"MRFTyreDepthAnsysCmd",
		"MRFTyreDepthAnsysCmd",
		(void *)NULL,
		"MRFTyreDepthAnsysHeader",
		CATFrmAvailable);

	CATAfrCommandHeader::CATCreateCommandHeader("MRFBackProfileCmdHdr",
		"MRFBackProfileCmd",
		"MRFBackProfileCmd",
		(void *)NULL,
		"MRFBackProfileHeader",
		CATFrmAvailable);
}

//-----------------------------------------------------------------------------
// CreateToolbars                                               CATIPRDWorkshopAddin
//-----------------------------------------------------------------------------
CATCmdContainer* MRFPrdAddin::CreateToolbars()
{
	
	NewAccess(CATCmdContainer, pMRFASSYSection, MRF); //Creates Section 

	NewAccess(CATCmdContainer, pMRFAssyContainer, MRFAssyTlb);
	AddAccessChild(pMRFASSYSection, pMRFAssyContainer);
	
	NewAccess (CATCmdStarter, pStarterMRFAssy, ButtonMRFAssy); 
	SetAccessCommand(pStarterMRFAssy, "MRFAssyCmdHdr"); //Provides access to command header
	SetAccessChild(pMRFAssyContainer, pStarterMRFAssy); // Adds the command under MRF Section

	NewAccess(CATCmdStarter, pStarterMRFTyreDepthAnsys, ButtonMRFTyreDepthAnsys);
	SetAccessCommand(pStarterMRFTyreDepthAnsys, "MRFTyreSurfDepthAnsysCmdHdr"); //Provides access to command header
	SetAccessNext(pStarterMRFAssy, pStarterMRFTyreDepthAnsys); // Adds the command under MRF Section

	NewAccess(CATCmdStarter, pStarterMRFBackProfile, ButtonMRFBackProfile);
	SetAccessCommand(pStarterMRFBackProfile, "MRFBackProfileCmdHdr"); //Provides access to command header
	SetAccessNext(pStarterMRFTyreDepthAnsys, pStarterMRFBackProfile); // Adds the command under MRF Section

	return pMRFASSYSection; // return Section
	
}



